<script setup lang="ts">
import type { DatePickerInstance } from "@vuepic/vue-datepicker";
import VueDatePicker from "@vuepic/vue-datepicker";
import "@vuepic/vue-datepicker/dist/main.css";
import { format, isSameDay } from "date-fns";

import Button from "../Button/index.vue";
import OutlinedButton from "../OutlinedButton/index.vue";
import SpinnerNumberInput from "../SpinnerNumberInput/index.vue";

const props = defineProps({
  modelValue: {
    type: [Date, Object as () => null],
    default: null,
  },
  id: {
    type: String,
    default: "",
  },
  label: {
    type: String,
    default: "",
  },
  placeholder: {
    type: String,
    default: "",
  },
  required: {
    type: Boolean,
    default: false,
  },
  disabled: {
    type: Boolean,
    default: false,
  },
  minDate: {
    type: Date || null,
    default: null,
  },
  maxDate: {
    type: Date || null,
    default: null,
  },
  color: {
    type: String as () =>  'primary' | 'success' | 'info' | 'warning' |'error',
    default: 'primary'
  }
});

const now = ref(new Date());

const selectedDate = ref<string | null>(null);
const selectedTime = ref<{ hours: number; minutes: number }>({
  hours: now.value.getHours(),
  minutes: now.value.getMinutes(),
});

const datePicker = ref<DatePickerInstance | null>(null);

const emit = defineEmits(["update:modelValue"]);

watch(
  () => props.modelValue,
  (value) => {
    if (!props.modelValue) {
      return null;
    }

    selectedDate.value = format(new Date(props.modelValue), "dd-MM-yyyy");
    emit("update:modelValue", value);
  },
  { immediate: true }
);

const isValidDateTime = computed(() => {
  if (!selectedDate.value) return false;

  const minDate = props.minDate ?? new Date();
  const minTime = { hours: minDate.getHours(), minutes: minDate.getMinutes() };

  const isSameAsMin = isSameDay(new Date(selectedDate.value!), minDate);

  const isValid = {
    hours: isSameAsMin ? selectedTime.value.hours >= minTime.hours : true,
    minutes:
      isSameAsMin && selectedTime.value.hours === minTime.hours
        ? selectedTime.value.minutes >= minTime.minutes
        : true,
  };

  return isValid.hours && isValid.minutes;
});

function onClickOpen() {
  selectedTime.value = {
    hours: props.modelValue
      ? props.modelValue?.getHours()
      : now.value.getHours(),
    minutes: props.modelValue
      ? props.modelValue?.getMinutes()
      : now.value.getMinutes(),
  };
}

const pickerClass = computed(() => `custom-date-picker date-picker-${props.color}`);
</script>

<template>
  <div class="flex flex-col items-start text-sm font-[600] text-gray-700">
    <label
      v-if="props.label"
      :for="id"
      class="mb-1.5 text-sm font-[600] text-gray-700"
      @click="datePicker?.openMenu()"
    >
      {{ props.label }}
      <span v-if="props.required" class="text-primary-500">*</span>
    </label>
    <vue-date-picker
      ref="datePicker"
      :id="props.id"
      :min-date="props.minDate"
      :max-date="props.maxDate"
      :model-value="props.modelValue as Date"
      :placeholder="props.placeholder as string"
      :format="(date: any) => (date ? format(date, 'dd/MM/yyyy, HH:mm') : '')"
      input-class-name="!py-2 !rounded-lg focus:!ring-primary-500"
      :disabled="props.disabled"
      calendar-cell-class-name="!rounded-full"
      :class="pickerClass"
      @open="onClickOpen"
      @date-update="
        selectedDate = format($event, 'dd-MM-yyyy');
        datePicker?.switchView('time');
      "
      @update:model-value="emit('update:modelValue', $event)"
    >
      <template #time-picker-overlay="{ hours, minutes, setHours, setMinutes }">
        <div class="py-5 px-8 space-y-5">
          <div class="flex flex-col items-center">
            <p class="font-medium mb-2 text-center">
              {{ selectedDate ?? "DD-MM-YYYY" }}
            </p>
            <div class="flex items-center space-x-3 w-3/4">
              <SpinnerNumberInput
                v-model="selectedTime.hours"
                id="inputPickupHour"
                :min="0"
                :max="23"
                @update:model-value="
                  (event: any) => {
                    selectedTime.hours = event;
                    setHours(selectedTime.hours);
                  }
                "
              />
              <span class="text-xl">:</span>
              <SpinnerNumberInput
                v-model="selectedTime.minutes"
                id="inputPickupMinute"
                :min="0"
                :max="59"
                @update:model-value="
                  (event: any) => {
                    selectedTime.minutes = event;
                    setMinutes(selectedTime.minutes);
                  }
                "
              />
            </div>
          </div>
        </div>
      </template>
      <template #action-row="{ modelValue, selectDate }">
        <div class="!w-full flex space-x-3">
          <OutlinedButton
            label="Cancel"
            class="w-full"
            :color="color"
            @on-click="datePicker?.closeMenu()"
          />
          <Button
            label="Confirm"
            class="w-full"
             :color="color"
            :disabled="!isValidDateTime"
            @on-click="selectDate"
          />
        </div>
      </template>
    </vue-date-picker>
  </div>
</template>

